#!/usr/bin/env bash
set -Eeuo pipefail
say() { printf '\033[1;36m[Aurora Installer]\033[0m %s\n' "$*"; }
die() { printf '\033[1;31m[错误]\033[0m %s\n' "$*" >&2; exit 1; }
command -v base64 >/dev/null 2>&1 || die "系统缺少 base64 命令"
command -v tar >/dev/null 2>&1 || die "系统缺少 tar 命令"
line=$(awk '/^__AURORA_PAYLOAD_BELOW__$/ {print NR + 1; exit}' "$0")
[[ -n "$line" ]] || die "安装包载荷损坏"
tmp=$(mktemp -d /tmp/aurora-panel.XXXXXX)
trap 'rm -rf "$tmp"' EXIT
tail -n +"$line" "$0" | base64 -d | tar -xzf - -C "$tmp"
[[ -x "$tmp/AuroraProxyPanel/install.sh" ]] || die "安装包解压失败"
if [[ -n "${AURORA_EXTRACT_ONLY:-}" ]]; then
  target=$AURORA_EXTRACT_ONLY
  mkdir -p "$target"
  cp -a "$tmp/AuroraProxyPanel/." "$target/"
  say "源码已解压到：$target"
  exit 0
fi
say "启动 Aurora Proxy Panel v2.3.1 部署程序……"
bash "$tmp/AuroraProxyPanel/install.sh" "$@"
exit $?
__AURORA_PAYLOAD_BELOW__

